// supabase/functions/update-news/news.ts: Fetches and processes news articles.
// @ts-nocheck
/// <reference types="https://esm.sh/@supabase/functions-js@2/src/edge-runtime.d.ts" />

import { Logger } from './logger.ts';
import { formatArticleBatchWithGemini } from './gemini.ts';
import { supabaseAdmin, markKeyUsed, markKeyFailed, logKeyAudit } from './supabase.ts';
import { delay } from './utils.ts';

const NEWS_API_URL = 'https://gnews.io/api/v4/top-headlines';

const fetchWithRetryAndRotation = async (
    url: string, 
    category: string,
    logger: Logger, 
    currentKeyObj: any,
    getFallbackKey: (failedKeyId: string, errorMsg: string) => Promise<any>,
    retries = 2
): Promise<{ response: Response, finalKeyObj: any }> => {
    if (!currentKeyObj) {
        throw new Error(`[${category}] No News API key assigned.`);
    }

    const originalUrl = new URL(url);
    try {
        originalUrl.searchParams.set('apikey', currentKeyObj.api_key);
        const response = await fetch(originalUrl.toString());

        if (!response.ok) {
            const isRateLimit = response.status === 429;
            const isAuthError = response.status === 401;
            const errorMsg = `GNews API Error: ${response.status} ${response.statusText}`;

            if ((isRateLimit || isAuthError) && retries > 0) {
                logger.warn(`[${category}] News API key (ending in ...${currentKeyObj.api_key.slice(-4)}) reached its limit or failed. Requesting a backup key...`);

                const newKeyObj = await getFallbackKey(currentKeyObj.id, errorMsg);

                if (!newKeyObj) {
                    throw new Error(`[${category}] All backup News API keys have failed or are exhausted.`);
                }

                // Log the fallback event
                await logKeyAudit(currentKeyObj.id, newKeyObj.id, category, errorMsg);

                logger.info(`[${category}] Switched to backup News API key (ending in ...${newKeyObj.api_key.slice(-4)}). Retrying...`);
                await delay(1000);
                return fetchWithRetryAndRotation(url, category, logger, newKeyObj, getFallbackKey, retries - 1);
            }
            throw new Error(errorMsg);
        }

        // Success
        await markKeyUsed(currentKeyObj.id, category);
        return { response, finalKeyObj: currentKeyObj };
    } catch (error: any) {
        if (retries > 0 && !error.message.includes('All backup')) {
            logger.warn(`[${category}] Temporary network error fetching news: ${error.message}. Retrying... (${retries} attempts left)`);
            await delay(2000);
            return fetchWithRetryAndRotation(url, category, logger, currentKeyObj, getFallbackKey, retries - 1);
        }
        throw error;
    }
};

export const processNewsCategory = async (
    category: string, 
    logger: Logger, 
    assignedGnewsKey: any, 
    assignedGeminiKey: any,
    getFallbackGnewsKey: (failedKeyId: string, errorMsg: string) => Promise<any>,
    getFallbackGeminiKey: (failedKeyId: string, errorMsg: string) => Promise<any>,
    config: Record<string, any>
) => {
  let articlesUpdated = 0;
  try {
    logger.info(`[${category}] Scouting the web for the latest news...`);
    const { response } = await fetchWithRetryAndRotation(
        `${NEWS_API_URL}?category=${category}&lang=en&max=10`, 
        category,
        logger, 
        assignedGnewsKey,
        getFallbackGnewsKey
    );

    const newsData = await response.json();
    if (newsData.totalArticles === 0) {
      logger.info(`[${category}] Hmm, looks like there's no new news right now. It's quiet out there.`);
      logger.addSummary(`[${category}] Fetched: 0 | Duplicates: 0 | Sent to AI: 0 | AI Formatted: 0 | AI Skipped: 0`);
      return { success: true, articlesUpdated: 0 };
    }

    const articles = newsData.articles;
    if (!articles || articles.length === 0) {
      logger.warn(`[${category}] The news source gave us a weird response. We'll try again later.`);
      logger.addSummary(`[${category}] Fetched: 0 | Duplicates: 0 | Sent to AI: 0 | AI Formatted: 0 | AI Skipped: 0`);
      return { success: true, articlesUpdated: 0 };
    }

    // --- Deduplication Logic & Robust Logging ---
    logger.info(`[${category}] Found ${articles.length} articles! Let's check if we already have any of these...`);

    // Fetch FULL existing articles so we can retain them if they are still in the latest news
    const { data: existingArticles } = await supabaseAdmin
        .from('public_news_articles')
        .select('*')
        .eq('category', category);

    const existingUrls = new Set(existingArticles?.map(a => a.article_data.url) || []);

    // Filter out duplicates. Only keep articles whose URL is NOT in the database.
    const newArticles = articles.filter((a: any) => !existingUrls.has(a.url));
    const duplicateCount = articles.length - newArticles.length;

    if (duplicateCount > 0) {
        logger.info(`[${category}] Ah, ${duplicateCount} of these are old news (duplicates). We'll skip them to save our AI's energy.`);
    }

    // Identify existing articles that are STILL in the latest fetched batch
    const currentFetchedUrls = new Set(articles.map(a => a.url));
    const retainedArticles = (existingArticles || [])
        .filter(a => currentFetchedUrls.has(a.article_data.url))
        .map(a => {
            // Strip id and created_at so they can be cleanly re-inserted
            const { id, created_at, ...rest } = a;
            return rest;
        });

    if (newArticles.length === 0) {
        logger.info(`[${category}] Looks like we already have all ${articles.length} of these articles. Nothing new for the AI to do here!`);
        logger.addSummary(`[${category}] Fetched: ${articles.length} | Duplicates: ${duplicateCount} | Sent to AI: 0 | AI Formatted: 0 | AI Skipped: 0`);

        // We still need to update the database to ONLY keep the latest articles (retainedArticles)
        logger.info(`[${category}] Tidying up the database, keeping the ${retainedArticles.length} articles that are still trending...`);
        await supabaseAdmin.from('public_news_articles').delete().eq('category', category);
        if (retainedArticles.length > 0) {
            await supabaseAdmin.from('public_news_articles').insert(retainedArticles);
        }
        return { success: true, articlesUpdated: retainedArticles.length };
    }

    logger.success(`[${category}] Sending ${newArticles.length} fresh, unique articles to the AI for a makeover...`);

    const formattedArticlesMap = await formatArticleBatchWithGemini(
        newArticles, 
        category,
        logger, 
        assignedGeminiKey,
        getFallbackGeminiKey,
        config
    );

    const successfulArticles = newArticles.map((article: any) => {
        const formattedData = formattedArticlesMap.get(article.url);
        if (formattedData) {
            const updatedArticleData = { ...article };
            updatedArticleData.title = formattedData.title; 

            return {
                category,
                article_data: updatedArticleData,
                formatted_content_md: { markdown: formattedData.markdown }
            };
        }
        return null;
    }).filter(Boolean);

    const successCount = successfulArticles.length;
    const aiSkippedCount = newArticles.length - successCount; // Articles AI refused to format

    logger.info(`[${category}] The AI is done! It beautifully formatted ${successCount} articles, and decided to skip ${aiSkippedCount}.`);
    logger.addSummary(`[${category}] Fetched: ${articles.length} | Duplicates: ${duplicateCount} | Sent to AI: ${newArticles.length} | AI Formatted: ${successCount} | AI Skipped: ${aiSkippedCount}`);

    const allArticlesToSave = [...retainedArticles, ...successfulArticles];

    if (allArticlesToSave.length === 0) {
      logger.warn(`[${category}] Nothing new to save this time around.`);
      return { success: true, articlesUpdated: 0 };
    }

    logger.info(`[${category}] Clearing out the old news for this category...`);
    const { error: deleteError } = await supabaseAdmin.from('public_news_articles').delete().eq('category', category);
    if (deleteError) throw new Error(`Database cleanup failed: ${deleteError.message}`);

    logger.info(`[${category}] Saving ${allArticlesToSave.length} articles to the database (${retainedArticles.length} old favorites + ${successfulArticles.length} brand new ones)...`);
    const { error: insertError } = await supabaseAdmin.from('public_news_articles').insert(allArticlesToSave);
    if (insertError) throw new Error(`Database save failed: ${insertError.message}`);

    articlesUpdated = allArticlesToSave.length;
    logger.success(`[${category}] Awesome! ${articlesUpdated} articles are now live and ready to read.`);
    return { success: true, articlesUpdated };
  } catch (error: any) {
    let simpleError = error.message.includes('GNews') ? "Failed to connect to the news source" : error.message;
    logger.error(`[${category}] Oops, hit a snag while updating this category: ${simpleError}`);
    return { success: false, articlesUpdated: 0 };
  }
};

// supabase/functions/update-news/gemini.ts: Service for interacting with the Google Gemini API.
// @ts-nocheck
/// <reference types="https://esm.sh/@supabase/functions-js@2/src/edge-runtime.d.ts" />

import { GoogleGenAI, Type } from 'https://esm.sh/@google/genai@^1.16.0';
import { Logger } from './logger.ts';
import { markKeyUsed, markKeyFailed, logKeyAudit } from './supabase.ts';

const BATCH_SYSTEM_PROMPT = `You are an expert news writer and article formatter. You will receive a JSON array of raw news articles. For EACH article, you MUST perform two tasks:
1.  **Generate a Display Title:** Create a concise, catchy, and SEO-friendly title that is 7-8 words long. This should capture the essence of the article.
2.  **Format the Article Body:** Rewrite the article's content into a detailed, long-form news article formatted with rich markdown, following the structure below precisely.

**Formatting Structure for EACH Article Body:**
1.  **Lead Paragraph:** Start with a single, strong introductory paragraph that hooks the reader and summarizes the most critical information (the who, what, where, when, and why).
2.  **Detailed Body:** Continue with a well-structured, multi-paragraph body that elaborates on the story. You MUST use subheadings (e.g., #### Background, #### The Details, #### What's Next) where appropriate to organize the content and improve readability. The goal is to create a comprehensive and engaging article, not just a brief summary.

**Output Requirement:**
You MUST respond with a single, valid JSON object containing TWO arrays:
1. \`formatted_articles\`: An array of objects for articles you successfully formatted. Each object MUST contain:
   - \`original_url\`: The URL of the article.
   - \`display_title\`: The new 7-8 word title.
   - \`formatted_markdown\`: The full markdown content you generated. (Use \n for newlines).
2. \`skipped_articles\`: An array of objects for articles you decided NOT to format (e.g., due to safety filters, insufficient content, or other reasons). Each object MUST contain:
   - \`original_url\`: The URL of the skipped article.
   - \`reason\`: A clear, concise reason explaining EXACTLY why you skipped it.

Handle each article independently. Do not fail the entire batch if one article is problematic.`;

export const generateAdminSummary = async (
    logger: Logger,
    status: string,
    geminiKeyObj: any,
    getFallbackKey: (failedKeyId: string, errorMsg: string) => Promise<any>,
    config: Record<string, any>
): Promise<string> => {
    if (!geminiKeyObj) return "No Gemini key available to generate summary.";

    const summaryText = logger.getSummary().join('\n');
    const logsText = logger.getLogs().join('\n');

    const prompt = `You are an AI assistant for the Ceaznet News Bot. 
The news update process just finished with status: ${status}.
Here is the summary:
${summaryText}

Here are the detailed logs:
${logsText}

Please write a concise, engaging, and professional summary of this update process for the system administrator. 
Highlight any errors, warnings, or notable successes. Keep it under 3 paragraphs. Format it using HTML (e.g., <p>, <strong>, <ul>) so it can be directly embedded in an email. Do not include markdown code blocks like \`\`\`html.`;

    let currentKeyObj = geminiKeyObj;
    let attempts = 0;
    const maxAttempts = 3;
    const modelName = config.summary_model || 'gemini-2.5-flash';

    logger.info(`Starting AI summary generation. Max attempts allowed: ${maxAttempts}`);

    while (attempts < maxAttempts) {
        attempts++;
        const attemptStartTime = Date.now();
        try {
            logger.info(`[Admin Summary] Attempt ${attempts}: Calling Gemini API (model: ${modelName}) with key ...${currentKeyObj.api_key.slice(-4)}`);
            const geminiAi = new GoogleGenAI({ apiKey: currentKeyObj.api_key });
            const response = await geminiAi.models.generateContent({ 
                model: modelName, 
                contents: prompt 
            });
            logger.success(`[Admin Summary] Attempt ${attempts} succeeded in ${Date.now() - attemptStartTime}ms.`);
            return response.text.trim();
        } catch (error: any) {
            const isRateLimitOrUnavailable = error.message.includes('429') || error.message.includes('503');
            const isAuthError = error.message.includes('API key not valid');

            logger.warn(`Admin summary generation failed on attempt ${attempts} with key ...${currentKeyObj.api_key.slice(-4)}. Error: ${error.message}`);

            if ((isRateLimitOrUnavailable || isAuthError) && attempts < maxAttempts) {
                logger.info(`Fetching a fallback Gemini key for admin summary...`);
                const newKeyObj = await getFallbackKey(currentKeyObj.id, error.message);

                if (newKeyObj) {
                    await logKeyAudit(currentKeyObj.id, newKeyObj.id, 'admin_summary', error.message);
                    currentKeyObj = newKeyObj;
                    // Add a small delay for 503s or 429s before retrying
                    if (isRateLimitOrUnavailable) {
                        await new Promise(resolve => setTimeout(resolve, 2000)); // 2 second backoff
                    }
                    continue; // Try again with new key
                } else {
                    logger.error(`No fallback Gemini keys available for admin summary.`);
                    break; // Exit loop if no fallback keys
                }
            } else {
                break; // Exit loop for other errors or max attempts reached
            }
        }
    }

    return `The automated news fetching and processing pipeline finished with status: ${status}. (AI summary generation failed after ${attempts} attempts)`;
};

export const formatArticleBatchWithGemini = async (
    articles: any[], 
    category: string,
    logger: Logger, 
    assignedKey: any,
    getFallbackKey: (failedKeyId: string, errorMsg: string) => Promise<any>,
    config: Record<string, any>
): Promise<Map<string, { title: string, markdown: string }>> => {
    if (articles.length === 0) return new Map();
    if (!assignedKey) {
        logger.error(`[${category}] We don't have an AI key for this job, so we can't format anything.`);
        return new Map();
    }

    let currentKeyObj = assignedKey;
    const articlesForPrompt = articles.map(a => ({
        title: a.title,
        source: a.source.name,
        url: a.url,
        content: a.content || a.description || ''
    }));
    const prompt = JSON.stringify(articlesForPrompt);
    let modelName = config.formatting_model || 'gemini-2.5-flash-lite';

    let attempts = 0;
    const maxAttempts = 3;

    while (attempts < maxAttempts) {
        attempts++;

        // Optimization: If the first attempt with lite fails, fallback to the standard flash model
        if (attempts > 1 && modelName === 'gemini-2.5-flash-lite') {
            modelName = 'gemini-2.5-flash';
            logger.info(`[${category}] Switching to heavier model (${modelName}) for retry...`);
        }

        const attemptStartTime = Date.now();
        try {
            logger.info(`[${category}] Attempt ${attempts}: Calling Gemini API (model: ${modelName}) with ${articlesForPrompt.length} articles using key ...${currentKeyObj.api_key.slice(-4)}`);
            const client = new GoogleGenAI({ apiKey: currentKeyObj.api_key });

            const response = await client.models.generateContent({
                model: modelName,
                contents: prompt,
                config: { 
                    systemInstruction: BATCH_SYSTEM_PROMPT, 
                    responseMimeType: 'application/json', 
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            formatted_articles: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        original_url: { type: Type.STRING },
                                        display_title: { type: Type.STRING },
                                        formatted_markdown: { type: Type.STRING }
                                    },
                                    required: ["original_url", "display_title", "formatted_markdown"]
                                }
                            },
                            skipped_articles: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        original_url: { type: Type.STRING },
                                        reason: { type: Type.STRING }
                                    },
                                    required: ["original_url", "reason"]
                                }
                            }
                        },
                        required: ["formatted_articles", "skipped_articles"]
                    } 
                },
            });

            const jsonText = response.text.trim();
            if (!jsonText) {
                 logger.warn(`[${category}] The AI gave us a blank stare (empty response). No articles formatted this time.`);
                 return new Map();
            }

            const results = JSON.parse(jsonText);
            const resultMap = new Map<string, { title: string, markdown: string }>();

            // Process successfully formatted articles
            if (results.formatted_articles) {
                for (const res of results.formatted_articles) {
                    if (res.original_url && res.formatted_markdown && res.display_title) {
                        resultMap.set(res.original_url, { title: res.display_title, markdown: res.formatted_markdown });
                    }
                }
            }

            // Process and log skipped articles
            if (results.skipped_articles && results.skipped_articles.length > 0) {
                for (const skipped of results.skipped_articles) {
                    if (skipped.original_url && skipped.reason) {
                        logger.warn(`[${category}] AI decided to skip an article. It said: "${skipped.reason}" (URL: ${skipped.original_url.slice(0, 30)}...)`);
                    }
                }
            }

            logger.success(`[${category}] High five! The AI (using key ...${currentKeyObj.api_key.slice(-4)}) successfully formatted ${resultMap.size} articles in ${Date.now() - attemptStartTime}ms.`);
            await markKeyUsed(currentKeyObj.id, category);
            return resultMap;

        } catch (error: any) {
            const isRateLimitOrUnavailable = error.message.includes('429') || error.message.includes('503');
            const isAuthError = error.message.includes('API key not valid');

            logger.warn(`[${category}] Formatting failed on attempt ${attempts} with key ...${currentKeyObj.api_key.slice(-4)}. Error: ${error.message}`);

            if ((isRateLimitOrUnavailable || isAuthError) && attempts < maxAttempts) {
                logger.info(`[${category}] Fetching a fallback Gemini key...`);
                const newKeyObj = await getFallbackKey(currentKeyObj.id, error.message);

                if (newKeyObj) {
                    await logKeyAudit(currentKeyObj.id, newKeyObj.id, category, error.message);
                    currentKeyObj = newKeyObj;
                    if (isRateLimitOrUnavailable) {
                        await new Promise(resolve => setTimeout(resolve, 2000));
                    }
                    continue;
                } else {
                    logger.error(`[${category}] No fallback Gemini keys available.`);
                    break;
                }
            } else {
                break;
            }
        }
    }
    return new Map();
};

// @ts-nocheck - This is a Deno file and should not be type-checked by the frontend's TypeScript compiler.
// FIX: Updated Supabase functions type reference to resolve type errors.
/// <reference types="https://esm.sh/@supabase/functions-js@2.4.1/src/edge-runtime.d.ts" />

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const supabaseUrl = Deno.env.get('SUPABASE_URL');
const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');

if (!supabaseUrl || !serviceRoleKey) {
  throw new Error("Supabase environment variables (SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY) are not set.");
}

export const supabaseAdmin = createClient(supabaseUrl, serviceRoleKey);

// Advanced Helper functions for updating key stats and logging
export const markKeyUsed = async (keyId: string, category: string) => {
  await supabaseAdmin.rpc('mark_news_key_used', { key_id: keyId, cat: category });
  // Ensure failure count is completely reset on success to fix the 24-hour exhaust loop
  await supabaseAdmin.from('news_api_keys').update({ failure_count: 0, status: 'active', cooldown_until: null }).eq('id', keyId);
};

export const markKeyFailed = async (keyId: string, errorMsg: string, maxFailures: number = 3) => {
  await supabaseAdmin.rpc('mark_news_key_failed', { key_id: keyId, err_msg: errorMsg, max_failures: maxFailures });
};

export const logKeyAudit = async (failedId: string, fallbackId: string, category: string, errorMsg: string) => {
  await supabaseAdmin.rpc('log_api_key_audit', { failed_id: failedId, fallback_id: fallbackId, cat: category, err: errorMsg });
};

export const getNewsSystemConfig = async () => {
  const { data, error } = await supabaseAdmin.from('news_system_config').select('*');
  if (error) {
    console.error("Error fetching news_system_config:", error);
    return {};
  }
  const config: Record<string, any> = {};
  data?.forEach(row => {
    config[row.config_key] = row.config_value;
  });
  return config;
};

// supabase/functions/update-news/email.ts: Service for sending email reports.
// @ts-nocheck - This is a Deno file and should not be type-checked by the frontend's TypeScript compiler.
/// <reference types="https://esm.sh/@supabase/functions-js@2/src/edge-runtime.d.ts" />

import { Logger } from './logger.ts';

import { generateAdminSummary } from './gemini.ts';
import { markKeyUsed, markKeyFailed } from './supabase.ts';

const LOG_RECIPIENT_EMAIL = Deno.env.get('LOG_RECIPIENT_EMAIL');
const LOG_SENDER_EMAIL = Deno.env.get('LOG_SENDER_EMAIL');

/**
 * Creates a simple HTML report with a summary table of the news update process.
 * @param logger The logger instance with all execution data.
 * @param status The overall status of the function run.
 * @returns A simple HTML string for the email body.
 */
function createSimpleHtmlReport(logger: Logger, status: 'SUCCESS' | 'FAILURE', adminMessage: string, triggerType: string): string {
    const summary = logger.getSummary();
    const statusColor = status === 'SUCCESS' ? '#10b981' : '#ef4444'; // Tailwind colors: emerald-500, red-500
    const generatedDate = new Date().toUTCString();

    let totalArticlesUpdated = 0;
    const categoryStats: Record<string, { fetched: number, duplicates: number, sentToAi: number, formatted: number, skipped: number }> = {};

    summary.forEach(line => {
        const totalMatch = line.match(/Total Articles Updated: (\d+)/);
        if (totalMatch) {
            totalArticlesUpdated = parseInt(totalMatch[1], 10);
        }

        // Parse the new robust summary format
        const categoryMatch = line.match(/\[(.*?)\] Fetched: (\d+) \| Duplicates: (\d+) \| Sent to AI: (\d+) \| AI Formatted: (\d+) \| AI Skipped: (\d+)/);
        if (categoryMatch) {
            const [, category, fetched, duplicates, sentToAi, formatted, skipped] = categoryMatch;
            categoryStats[category] = {
                fetched: parseInt(fetched, 10),
                duplicates: parseInt(duplicates, 10),
                sentToAi: parseInt(sentToAi, 10),
                formatted: parseInt(formatted, 10),
                skipped: parseInt(skipped, 10),
            };
        }
    });

    const tableRows = Object.entries(categoryStats).map(([category, stats]) => `
        <tr>
            <td style="padding: 12px 4px; border-bottom: 1px dashed #eaeaea; text-transform: uppercase; font-weight: 400; color: #333; letter-spacing: 1px; font-size: 11px; text-align: left;">${category}</td>
            <td style="padding: 12px 4px; border-bottom: 1px dashed #eaeaea; text-align: center; color: #666; font-family: 'JetBrains Mono', monospace; font-size: 13px; font-weight: 300;">${stats.fetched}</td>
            <td style="padding: 12px 4px; border-bottom: 1px dashed #eaeaea; text-align: center; color: #aaa; font-family: 'JetBrains Mono', monospace; font-size: 13px; font-weight: 300;">${stats.duplicates}</td>
            <td style="padding: 12px 4px; border-bottom: 1px dashed #eaeaea; text-align: center; color: #666; font-family: 'JetBrains Mono', monospace; font-size: 13px; font-weight: 300;">${stats.sentToAi}</td>
            <td style="padding: 12px 4px; border-bottom: 1px dashed #eaeaea; text-align: center; color: #10b981; font-family: 'JetBrains Mono', monospace; font-size: 13px; font-weight: 400;">${stats.formatted}</td>
            <td style="padding: 12px 4px; border-bottom: 1px dashed #eaeaea; text-align: center; color: ${stats.skipped > 0 ? '#ef4444' : '#aaa'}; font-family: 'JetBrains Mono', monospace; font-size: 13px; font-weight: 400;">${stats.skipped}</td>
        </tr>
    `).join('');

    return `
    <!DOCTYPE html>
    <html lang="en">
    <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>Ceaznet News Update Report</title>
        <style>
            @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400&family=JetBrains+Mono:wght@300;400&display=swap');

            body { 
                font-family: 'Outfit', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; 
                color: #444; 
                line-height: 1.5; 
                background-color: #ffffff; 
                margin: 0;
                padding: 15px 10px;
                font-weight: 300;
            }
            .wrapper { 
                max-width: 600px; 
                margin: 0 auto; 
            }
            h1 { 
                font-size: 22px; 
                margin: 0 0 15px 0; 
                font-weight: 400; 
                letter-spacing: -0.5px;
                color: #111;
                text-align: left;
            }
            .admin-message {
                font-size: 13px;
                color: #555;
                line-height: 1.6;
                margin-bottom: 25px;
                padding: 15px;
                background-color: #fcfcfc;
                border-left: 3px solid ${statusColor};
            }

            /* Meta Table (replaces flexbox) */
            .meta-table {
                width: 100%;
                border-collapse: collapse;
                margin-bottom: 20px;
                border-bottom: 1px solid #eee;
                padding-bottom: 15px;
            }
            .meta-table td {
                padding: 4px 0;
            }
            .meta-label {
                font-size: 10px;
                color: #888;
                text-transform: uppercase;
                letter-spacing: 1px;
                width: 80px;
                text-align: left;
            }
            .meta-value {
                font-family: 'JetBrains Mono', monospace;
                font-size: 12px;
                color: #333;
                text-align: right;
            }

            /* Main Data Table */
            .data-table { 
                width: 100%; 
                border-collapse: collapse; 
            }
            .data-table th { 
                text-align: center; 
                padding: 8px 2px; 
                border-bottom: 1px solid #ddd; 
                color: #aaa; 
                font-weight: 400; 
                font-size: 9px;
                text-transform: uppercase;
                letter-spacing: 1px;
            }
            .data-table th:first-child { text-align: left; }

            /* Footer Table (replaces flexbox) */
            .footer-table {
                width: 100%;
                border-collapse: collapse;
                margin-top: 30px;
                border-top: 1px solid #eee;
                padding-top: 15px;
            }
            .footer-table td {
                padding: 4px 0;
            }
            .footer-label {
                font-size: 10px;
                color: #888;
                text-transform: uppercase;
                letter-spacing: 0.5px;
                text-align: left;
            }
            .footer-val {
                font-size: 10px;
                font-family: 'JetBrains Mono', monospace;
                color: #555;
                text-align: right;
            }
        </style>
    </head>
    <body>
        <div class="wrapper">
            <h1>System Update</h1>

            <div class="admin-message">
                ${adminMessage}
            </div>

            <table class="meta-table">
                <tr>
                    <td class="meta-label">Status</td>
                    <td class="meta-value" style="color: ${statusColor};">${status.toUpperCase()}</td>
                </tr>
                <tr>
                    <td class="meta-label">Updated</td>
                    <td class="meta-value">${totalArticlesUpdated} Articles</td>
                </tr>
                <tr>
                    <td class="meta-label">Time</td>
                    <td class="meta-value">${generatedDate}</td>
                </tr>
            </table>

            <table class="data-table">
                <thead>
                    <tr>
                        <th>Category</th>
                        <th>Fetch</th>
                        <th>Dupe</th>
                        <th>To AI</th>
                        <th>Done</th>
                        <th>Skip</th>
                    </tr>
                </thead>
                <tbody>
                    ${tableRows}
                </tbody>
            </table>

            <table class="footer-table">
                <tr>
                    <td class="footer-label">Execution Environment</td>
                    <td class="footer-val">Supabase Edge Function</td>
                </tr>
                <tr>
                    <td class="footer-label">Database</td>
                    <td class="footer-val">Supabase PostgreSQL</td>
                </tr>
                <tr>
                    <td class="footer-label">AI Model</td>
                    <td class="footer-val">Gemini 2.5 Flash</td>
                </tr>
                <tr>
                    <td class="footer-label">News Source</td>
                    <td class="footer-val">GNews API</td>
                </tr>
                <tr>
                    <td class="footer-label">Trigger Type</td>
                    <td class="footer-val">${triggerType}</td>
                </tr>
                <tr>
                    <td class="footer-label">System Version</td>
                    <td class="footer-val">Ceaznet v2.8</td>
                </tr>
            </table>
        </div>
    </body>
    </html>
    `;
}


export async function sendEmailLog(
  logger: Logger, 
  status: 'SUCCESS' | 'FAILURE', 
  brevoKeyObj: any, 
  geminiKeyObj: any,
  getGeminiFallbackKey: (failedKeyId: string, errorMsg: string) => Promise<any>,
  config: Record<string, any>,
  triggerType: string
) {
  if (!LOG_RECIPIENT_EMAIL || !LOG_SENDER_EMAIL) {
    logger.error('Email service env vars not set. Skipping email.');
    return;
  }
  if (!brevoKeyObj) {
    logger.error('No Brevo API key available in the database. Skipping email.');
    return;
  }

  // Generate AI Summary
  logger.info('Generating AI summary for the email report...');
  const adminMessage = await generateAdminSummary(logger, status, geminiKeyObj, getGeminiFallbackKey, config);

  const subject = `Ceaznet News Update Report: ${status.toUpperCase()}`;
  const htmlContent = createSimpleHtmlReport(logger, status, adminMessage, triggerType);

  const emailPayload = {
    sender: { name: 'Ceaznet Bot', email: LOG_SENDER_EMAIL },
    to: [{ email: LOG_RECIPIENT_EMAIL }],
    subject,
    htmlContent: htmlContent,
  };

  try {
    const emailStartTime = Date.now();
    logger.info(`Sending email via Brevo API using key ...${brevoKeyObj.api_key.slice(-4)}`);

    // Log a sanitized version of the payload
    const sanitizedPayload = { ...emailPayload, htmlContent: '[HTML CONTENT HIDDEN FOR LOGS]' };
    logger.info(`Email Payload: ${JSON.stringify(sanitizedPayload)}`);

    const response = await fetch('https://api.brevo.com/v3/smtp/email', {
      method: 'POST',
      headers: { 'accept': 'application/json', 'api-key': brevoKeyObj.api_key, 'content-type': 'application/json' },
      body: JSON.stringify(emailPayload),
    });

    if (!response.ok) {
        const errorBody = await response.text();
        throw new Error(`Brevo API Error: ${response.status} ${response.statusText} - ${errorBody}`);
    }

    const responseData = await response.json();
    logger.success(`Successfully sent email report in ${Date.now() - emailStartTime}ms. Status: ${response.status} ${response.statusText}. Receipt (Message ID): ${responseData.messageId}`);
    await markKeyUsed(brevoKeyObj.id, 'email_report');
  } catch (error) {
    logger.error(`Email send failed: ${error.message}`);
    await markKeyFailed(brevoKeyObj.id, error.message, 3);
  }
}

